def _bigquery_routine_to_nested(bigquery_routine: BigqueryRoutine) -> BigqueryRoutineNested:
    """Convert flat BigqueryRoutine to nested format."""
    attrs = BigqueryRoutineAttributes()
    _populate_bigquery_routine_attrs(attrs, bigquery_routine)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        bigquery_routine, _BIGQUERY_ROUTINE_REL_FIELDS, BigqueryRoutineRelationshipAttributes
    )
    return BigqueryRoutineNested(
        guid=bigquery_routine.guid,
        type_name=bigquery_routine.type_name,
        status=bigquery_routine.status,
        version=bigquery_routine.version,
        create_time=bigquery_routine.create_time,
        update_time=bigquery_routine.update_time,
        created_by=bigquery_routine.created_by,
        updated_by=bigquery_routine.updated_by,
        classifications=bigquery_routine.classifications,
        classification_names=bigquery_routine.classification_names,
        meanings=bigquery_routine.meanings,
        labels=bigquery_routine.labels,
        business_attributes=bigquery_routine.business_attributes,
        custom_attributes=bigquery_routine.custom_attributes,
        pending_tasks=bigquery_routine.pending_tasks,
        proxy=bigquery_routine.proxy,
        is_incomplete=bigquery_routine.is_incomplete,
        provenance_type=bigquery_routine.provenance_type,
        home_id=bigquery_routine.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )

def _bigquery_routine_from_nested(nested: BigqueryRoutineNested) -> BigqueryRoutine:
    """Convert nested format to flat BigqueryRoutine."""
    attrs = nested.attributes if nested.attributes is not UNSET else BigqueryRoutineAttributes()
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _BIGQUERY_ROUTINE_REL_FIELDS,
        BigqueryRoutineRelationshipAttributes
    )
    return BigqueryRoutine(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_bigquery_routine_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )

def _bigquery_routine_to_nested_bytes(bigquery_routine: BigqueryRoutine, serde: Serde) -> bytes:
    """Convert flat BigqueryRoutine to nested JSON bytes."""
    return serde.encode(_bigquery_routine_to_nested(bigquery_routine))


def _bigquery_routine_from_nested_bytes(data: bytes, serde: Serde) -> BigqueryRoutine:
    """Convert nested JSON bytes to flat BigqueryRoutine."""
    nested = serde.decode(data, BigqueryRoutineNested)
    return _bigquery_routine_from_nested(nested)

